function buildPage(){addCodeBlockHighlighting(),addHeroLogo(),attachFilePathsToCodeBlocks(),addMediumZoom(),setLinkAttrs(),addAnchors()}function addCodeBlockHighlighting(){hljs.addPlugin(new CopyButtonPlugin),hljs.highlightAll()}function addHeroLogo(){const e=document.querySelector("main"),t=document.querySelector("h1");if(e||console.log("Document has no <main> element. Check the HTML template."),!t)return void console.log("Document has no <h1>. All documents must have an <h1>.");const o=t.cloneNode(!0),n=document.createElement("div"),d=document.createElement("div"),a=document.createElement("img");n.setAttribute("id","hero"),a.setAttribute("alt","Logo"),a.setAttribute("class","no-zoom"),a.setAttribute("src","https://seb-bh.github.io/universal-resources-internal/static/v2/assets/hero-logo.png"),d.appendChild(a),n.appendChild(d),n.appendChild(o),t.remove(),e.prepend(n)}function attachFilePathsToCodeBlocks(){document.querySelectorAll("p").forEach(function(e){"PRE"===e.nextElementSibling?.nodeName&&1===e.childNodes.length&&"CODE"===e.childNodes[0]?.nodeName&&(e.classList.add("collapse"),e.childNodes[0].classList.add("codeblock-filepath"))})}function addMediumZoom(){document.querySelector("main")&&mediumZoom(document.querySelectorAll("main img:not(.no-zoom)"),{margin:24,background:null})}function setLinkAttrs(){document.querySelectorAll("a").forEach(e=>{e.getAttribute("href").startsWith("/")||e.setAttribute("target","_blank")})}function addAnchors(){anchors.add("h2:not(.no-anchor), h3:not(.no-anchor), h4:not(.no-anchor), h5:not(.no-anchor)")}"loading"===document.readyState?document.addEventListener("DOMContentLoaded",buildPage):buildPage();
